/**
 * Canvas Slice
 *
 * State management for the infinite canvas: viewport, zoom, pan, layers.
 * Optimized for 60fps WebGL rendering with deck.gl.
 *
 * @see specs/006-user-interface.md Section 6.3
 */

import { createSlice } from '@belt/tools';
import type { ZoomLevel, ViewportBounds, LayerVisibility, CanvasSelection } from '../types';

// =============================================================================
// Constants
// =============================================================================

export const ZOOM_THRESHOLDS = {
  STRATEGIC: { min: 0, max: 4, granularity: 'year' as const },
  TACTICAL_WIDE: { min: 4, max: 8, granularity: 'month' as const },
  TACTICAL: { min: 8, max: 12, granularity: 'week' as const },
  OPERATIONAL: { min: 12, max: 16, granularity: 'day' as const },
  DETAIL: { min: 16, max: 20, granularity: 'hour' as const },
};

export function getZoomLevelName(zoom: number): ZoomLevel {
  if (zoom < ZOOM_THRESHOLDS.TACTICAL_WIDE.min) return 'STRATEGIC';
  if (zoom < ZOOM_THRESHOLDS.TACTICAL.min) return 'TACTICAL_WIDE';
  if (zoom < ZOOM_THRESHOLDS.OPERATIONAL.min) return 'TACTICAL';
  if (zoom < ZOOM_THRESHOLDS.DETAIL.min) return 'OPERATIONAL';
  return 'DETAIL';
}

// =============================================================================
// Canvas Slice State
// =============================================================================

interface AnimationTarget {
  zoom: number | null;
  panX: number | null;
  panY: number | null;
}

export interface CanvasSliceState {
  zoom: number;
  panX: number;
  panY: number;
  zoomLevel: ZoomLevel;
  viewport: ViewportBounds;
  layers: LayerVisibility;
  selection: CanvasSelection;
  todayDate: string;
  isViewportLocked: boolean;
  showMinimap: boolean;
  showGrid: boolean;
  isPerformanceMode: boolean;
  isPanning: boolean;
  isZooming: boolean;
  animationTarget: AnimationTarget;
  [key: string]: unknown;
}

const initialCanvasState: CanvasSliceState = {
  zoom: 10,
  panX: 0,
  panY: 0,
  zoomLevel: 'TACTICAL',
  viewport: {
    startDate: new Date().toISOString().split('T')[0],
    endDate: new Date(Date.now() + 84 * 24 * 60 * 60 * 1000).toISOString().split('T')[0],
    trainIds: [],
  },
  layers: {
    pmBlocks: true,
    complianceWindows: true,
    manhourOverlay: false,
    driftOverlay: false,
    baselineShadow: false,
  },
  selection: {
    selectedPmIds: [],
    selectedTrainIds: [],
    isMultiSelect: false,
  },
  todayDate: new Date().toISOString().split('T')[0],
  isViewportLocked: false,
  showMinimap: true,
  showGrid: true,
  isPerformanceMode: false,
  isPanning: false,
  isZooming: false,
  animationTarget: {
    zoom: null,
    panX: null,
    panY: null,
  },
};

export const canvasSlice = createSlice({
  id: 'canvas',
  initial: initialCanvasState,
  cache: { policy: 'session' },
  reducers: {
    // Viewport Control
    setZoom: (s, zoom: number) => {
      const state = s as CanvasSliceState;
      const clampedZoom = Math.max(0, Math.min(20, zoom));
      state.zoom = clampedZoom;
      state.zoomLevel = getZoomLevelName(clampedZoom);
    },

    zoomIn: (s, factor = 1.2) => {
      const state = s as CanvasSliceState;
      const newZoom = Math.min(20, state.zoom * factor);
      state.zoom = newZoom;
      state.zoomLevel = getZoomLevelName(newZoom);
    },

    zoomOut: (s, factor = 1.2) => {
      const state = s as CanvasSliceState;
      const newZoom = Math.max(0, state.zoom / factor);
      state.zoom = newZoom;
      state.zoomLevel = getZoomLevelName(newZoom);
    },

    setZoomLevel: (s, level: ZoomLevel) => {
      const state = s as CanvasSliceState;
      const thresholds = ZOOM_THRESHOLDS[level];
      const targetZoom = (thresholds.min + thresholds.max) / 2;
      state.zoom = targetZoom;
      state.zoomLevel = level;
    },

    setPan: (s, payload: { x: number; y: number }) => {
      const state = s as CanvasSliceState;
      state.panX = payload.x;
      state.panY = payload.y;
    },

    pan: (s, delta: { dx: number; dy: number }) => {
      const state = s as CanvasSliceState;
      state.panX += delta.dx;
      state.panY += delta.dy;
    },

    setViewport: (s, viewport: Partial<ViewportBounds>) => {
      const state = s as CanvasSliceState;
      state.viewport = { ...state.viewport, ...viewport };
    },

    // Layer Control
    setLayerVisibility: (s, layers: Partial<LayerVisibility>) => {
      const state = s as CanvasSliceState;
      state.layers = { ...state.layers, ...layers };
    },

    toggleLayer: (s, layer: keyof LayerVisibility) => {
      const state = s as CanvasSliceState;
      state.layers[layer] = !state.layers[layer];
    },

    showAllLayers: (s) => {
      const state = s as CanvasSliceState;
      state.layers = {
        pmBlocks: true,
        complianceWindows: true,
        manhourOverlay: true,
        driftOverlay: true,
        baselineShadow: true,
      };
    },

    hideAllOverlays: (s) => {
      const state = s as CanvasSliceState;
      state.layers.manhourOverlay = false;
      state.layers.driftOverlay = false;
      state.layers.baselineShadow = false;
    },

    // Selection
    selectPm: (s, pmId: string) => {
      const state = s as CanvasSliceState;
      if (state.selection.isMultiSelect) {
        if (!state.selection.selectedPmIds.includes(pmId)) {
          state.selection.selectedPmIds.push(pmId);
        }
      } else {
        state.selection.selectedPmIds = [pmId];
      }
    },

    deselectPm: (s, pmId: string) => {
      const state = s as CanvasSliceState;
      state.selection.selectedPmIds = state.selection.selectedPmIds.filter((id) => id !== pmId);
    },

    selectTrain: (s, trainId: string) => {
      const state = s as CanvasSliceState;
      if (state.selection.isMultiSelect) {
        if (!state.selection.selectedTrainIds.includes(trainId)) {
          state.selection.selectedTrainIds.push(trainId);

